#include <stdio.h>
int main(){
    int l,b,h;
    printf("enter the value of length of cuboid : ");
    scanf("%d",&l);
    printf("enter the value of breadth of cuboid : ");
    scanf("%d",&b);
    printf("enter the value of height of cuboid : ");
    scanf("%d",&h);
    printf("the value of volume of cuboid : %d",l*b*h);
}